    logic j_mem_ren_o;
    logic [ $clog2(num_spin / parallelism)-1 : 0 ] j_raddr_o;
    logic [ num_spin*bit_j*parallelism-1 : 0 ] j_rdata_i;
    logic h_ren_o;
    logic [ bit_h*num_spin-1 : 0 ] h_rdata_i;
    logic sfc_ren_o;
    logic [ scaling_bit-1 : 0 ] sfc_rdata_i;
